#include <Wire.h>
#include <Adafruit_MAX31865.h>
#include <Adafruit_SSD1306.h>
#include <SD.h>
#define MAX_CS 8
#define IGN_PIN 9
#define SD_CS 10
#define WATER_G 2000.0f
#define Cp_W 4.186f
#define Cv_BOMB 1550.0f
#define BASELINE_S 120
#define POST_S 180
Adafruit_MAX31865 rtd(MAX_CS);
Adafruit_SSD1306 oled(128,64,&Wire,-1);
File lg;
float g_T0=0,g_Tpeak=-999;
bool fired=false,done=false;
unsigned long fireTime=0;
float bomb_calorimeter_enthalpy(float T0,float Tpk,float CvB,float wg,float Cpw){
  return -(CvB+wg*Cpw)*(Tpk-T0);
}
void initHardware(){
  rtd.begin(MAX31865_3WIRE);pinMode(IGN_PIN,OUTPUT);
  oled.begin(SSD1306_SWITCHCAPVCC,0x3C);oled.clearDisplay();
  SD.begin(SD_CS);lg=SD.open("bomb.csv",FILE_WRITE);
  if(lg)lg.println("t_s,T_C,phase");
  Serial.begin(9600);
}
float readPT100Temperature(){return rtd.temperature(100,430.0f);}
void logPhaseSD(unsigned long t,float T,const char*ph){
  if(lg){lg.print(t);lg.print(',');lg.print(T,3);lg.print(',');lg.println(ph);lg.flush();}
}
void updateOLEDDisplay(float T,float dH,bool showDH){
  oled.clearDisplay();oled.setTextSize(1);oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,0);oled.print(fired?"COMBUSTION":"BASELINE");
  oled.setCursor(0,12);oled.print("T:");oled.print(T,2);oled.print("C");
  if(showDH){oled.setCursor(0,28);oled.print("dH=");oled.print(dH/1000.0f,2);oled.print("kJ");}
  oled.display();
}
void checkFaultSafety(float T){
  if(T>95.0f){Serial.println("FAULT:OVERTEMP");lg.close();while(1);}
}
void setup(){
  initHardware();
  Serial.println("Baseline phase 120s");
  for(int i=0;i<BASELINE_S;i++){
    float T=readPT100Temperature();checkFaultSafety(T);
    logPhaseSD(i,T,"baseline");updateOLEDDisplay(T,0,false);delay(1000);
  }
  g_T0=readPT100Temperature();
  digitalWrite(IGN_PIN,HIGH);delay(150);digitalWrite(IGN_PIN,LOW);
  fired=true;fireTime=millis();Serial.println("IGNITION");
}
void loop(){
  if(done)return;
  static unsigned long prev=0;unsigned long now=millis();
  if(now-prev<1000)return;prev=now;
  float T=readPT100Temperature();checkFaultSafety(T);
  if(T>g_Tpeak)g_Tpeak=T;
  logPhaseSD(now/1000,T,"combustion");
  updateOLEDDisplay(T,0,false);
  if(fired&&now-fireTime>POST_S*1000UL){
    float dH=bomb_calorimeter_enthalpy(g_T0,g_Tpeak,Cv_BOMB,WATER_G,Cp_W);
    Serial.print("dH_comb=");Serial.print(dH/1000.0f,3);Serial.println("kJ");
    if(lg){lg.print("dH_kJ=");lg.println(dH/1000.0f,3);lg.close();}
    updateOLEDDisplay(g_Tpeak,dH,true);
    done=true;
  }
}
